import java.util.ArrayList;import java.util.List;import java.util.Map;
final class InterpreterPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}interface Expression{boolean interpret(Map<String,Integer>context,int[]counter);}record Comparison(String left,String operator,String right)implements Expression{private int resolve(String token,Map<String,Integer>context){try{return Integer.parseInt(token);}catch(NumberFormatException ignored){Integer value=context.get(token);if(value==null)throw new PatternException("unknown_identifier");return value;}}public boolean interpret(Map<String,Integer>context,int[]counter){counter[0]++;int a=resolve(left,context),b=resolve(right,context);return operator.equals(">=")?a>=b:a==b;}}record And(List<Expression>children)implements Expression{public boolean interpret(Map<String,Integer>context,int[]counter){for(Expression child:children)if(!child.interpret(context,counter))return false;return true;}}
static Expression parse(String text){String[]tokens=text.trim().isEmpty()?new String[0]:text.trim().split("\\s+");List<Expression>children=new ArrayList<>();for(int i=0;i<tokens.length;){if(i+2>=tokens.length)throw new PatternException("invalid_expression");String operator=tokens[i+1];if(!operator.equals(">=")&&!operator.equals("=="))throw new PatternException("unsupported_operator");children.add(new Comparison(tokens[i],operator,tokens[i+2]));i+=3;if(i<tokens.length){if(!tokens[i].equals("and"))throw new PatternException("invalid_expression");i++;}}if(children.isEmpty())throw new PatternException("invalid_expression");return new And(children);}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Map<String,Integer>context=new java.util.LinkedHashMap<>();((Map<String,Object>)input.getOrDefault("context",Map.of())).forEach((k,v)->context.put(k,((Number)v).intValue()));int[]counter={0};boolean allowed=parse(String.valueOf(input.get("expression"))).interpret(context,counter);return Map.of("allowed",allowed,"comparisons",counter[0]);}}
